import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

const initialProducts = [
  { id: 1, name: 'Laptop', price: 999, inventory: 14, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 36, availability: 'In stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 9, availability: 'Low stock' },
  { id: 4, name: 'Headphones', price: 199, inventory: 0, availability: 'Out of stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 22, availability: 'In stock' },
];

let products = initialProducts;
let lastSyncedAt = new Date();
let syncJob = null;
let syncCount = 0;

export async function getAllProducts() {
  // Simulate the read path that would normally hit a database or API.
  await new Promise((resolve) => setTimeout(resolve, 100));
  return products;
}

export async function getCatalogSnapshot() {
  return {
    products: await getAllProducts(),
    lastSyncedAt,
    syncCount,
  };
}

export function scheduleCatalogSync(onComplete) {
  if (syncJob) {
    return syncJob;
  }

  syncJob = new Promise((resolve) => {
    setTimeout(async () => {
      syncCount += 1;
      lastSyncedAt = new Date();
      products = initialProducts.map((product, index) => {
        const delta = syncCount * (index + 1) * 3;
        const inventory = Math.max(0, product.inventory - syncCount * (index + 1));

        return {
          ...product,
          price: product.price + delta,
          inventory,
          availability: inventory === 0 ? 'Out of stock' : inventory < 10 ? 'Low stock' : 'In stock',
        };
      });

      try {
        await onComplete?.();
      } finally {
        syncJob = null;
        resolve();
      }
    }, 1200);
  });

  return syncJob;
}

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  experimental: {
    cacheComponents: true,
  },
};

export default nextConfig;
